#include <bits/stdc++.h>
using namespace std;
int n,ans=52;
bool use[4][14];
int main(){
	//freopen("poker.in","r",stdin);
	//freopen("poker.out","w",stdout);
	scanf("%d",&n);
	for(int i=1;i<=n;i++){
		string s;
		cin>>s;
		int u,v;
		if(s[0]=='D')
			u=0;
		else if(s[0]=='C')
			u=1;
		else if(s[0]=='H')
			u=2;
		else
			u=3;
		if(s[1]>='2' && s[1]<='9')
			v=s[1]-'0';
		else if(s[1]=='A')
			v=1;
		else if(s[1]=='T')
			v=10;
		else if(s[1]=='J')
			v=11;
		else if(s[1]=='Q')
			v=12;
		else if(s[1]=='K')
			v=13;
		if(!use[u][v])
			ans--,use[u][v]=1;
	}
	printf("%d",ans);
	return 0;
}
